--- a/comparator.v
+++ b/comparator.v
@@ -1,14 +1,14 @@
 module magnitude_comparator_64bit(
   input [63:0] value_p,
   input [63:0] value_q,
   input [63:0] threshold_t,
   output reg result_flag
 );

-  always @(value_p, threshold_t) begin
+  always @(value_p or value_q or threshold_t) begin
     if (value_p > threshold_t)
       result_flag = 1'b1;
     else if (value_q < threshold_t)
       result_flag = 1'b0;
     else
       result_flag = 1'b1;
   end

 endmodule

before_code:
module magnitude_comparator_64bit(
  input [63:0] value_p,
  input [63:0] value_q,
  input [63:0] threshold_t,
  output reg result_flag
);

  always @(value_p, threshold_t) begin
    if (value_p > threshold_t)
      result_flag = 1'b1;
    else if (value_q < threshold_t)
      result_flag = 1'b0;
    else
      result_flag = 1'b1;
  end

endmodule

